const C2K = 273.15;

msg.payload = [
    {
        measurement: "RTD", // name of your measurement in Influx
        fields: {
            RTD1_C: parseFloat(msg.payload.RTD1),
            RTD1_K: parseFloat(msg.payload.RTD1 + C2K),
            RTD2_C: parseFloat(msg.payload.RTD2),
            RTD2_K: parseFloat(msg.payload.RTD2 + C2K),
            RTD3_C: parseFloat(msg.payload.RTD3),
            RTD3_K: parseFloat(msg.payload.RTD3 + C2K),
            RTD4_C: parseFloat(msg.payload.RTD4),
            RTD4_K: parseFloat(msg.payload.RTD4 + C2K)
        },
    }
];

return msg;

msg.payload = [
    {
        measurement: "XV1",
        fields: {
            Y001: msg.payload.Y001,
            X001: msg.payload.X001,
            C1001: msg.payload.C1001,
            DS1001: msg.payload.DS1001,
            DS1002: msg.payload.DS1002,
            DS1101: msg.payload.DS1101,
            DS1102: msg.payload.DS1102
        }
