            C1002: msg.payload.C1002,
            DS1003: msg.payload.DS1003,
            DS1004: msg.payload.DS1004,
            DS1103: msg.payload.DS1103,
            DS1104: msg.payload.DS1104
        }
    }
];

return msg;

msg.payload = [
    {
