            C1003: msg.payload.C1003,
            DS1005: msg.payload.DS1005,
            DS1006: msg.payload.DS1006,
            DS1105: msg.payload.DS1105,
            DS1106: msg.payload.DS1106
        }
    }
];

return msg;

msg.payload = [
    {
        measurement: "PLC_ADC", // name of your measurement in Influx
        fields: {
            ADC3_raw: parseFloat(msg.payload.ADC3_raw),
            ADC3_filt: parseFloat(msg.payload.ADC3_filt)
        },
    }
