return msg;

msg.payload = [
    {
        measurement: "PLC_PID1", // name of your measurement in Influx
        fields: {
            PID1_SP: parseFloat(msg.payload.PID1_SP),
            PID1_Kp: parseFloat(msg.payload.PID1_Kp),
            PID1_Ki: parseFloat(msg.payload.PID1_Ki),
            PID1_Kd: parseFloat(msg.payload.PID1_Kd),
            PID1_PV: parseFloat(msg.payload.PID1_PV),
            PID1_rawPV: parseFloat(msg.payload.PID1_rawPV),
            PID1_Bias: parseFloat(msg.payload.PID1_Bias),
            PID1_Output: parseFloat(msg.payload.PID1_Output)
        },
    }
];

return msg;

msg.payload = [
    {
        measurement: "PLC_PID2", // name of your measurement in Influx
        fields: {
            PID2_SP: parseFloat(msg.payload.PID2_SP),
            PID2_Kp: parseFloat(msg.payload.PID2_Kp),
            PID2_Ki: parseFloat(msg.payload.PID2_Ki),
            PID2_Kd: parseFloat(msg.payload.PID2_Kd),
            PID2_PV: parseFloat(msg.payload.PID2_PV),
            PID2_rawPV: parseFloat(msg.payload.PID2_rawPV),
            PID2_Bias: parseFloat(msg.payload.PID2_Bias),
            PID2_Output: parseFloat(msg.payload.PID2_Output)
        },
    }
];

return msg;

msg.payload = [
    {
        measurement: "PLC_PID3", // name of your measurement in Influx
        fields: {
            PID3_SP: parseFloat(msg.payload.PID3_SP),
            PID3_Kp: parseFloat(msg.payload.PID3_Kp),
            PID3_Ki: parseFloat(msg.payload.PID3_Ki),
            PID3_Kd: parseFloat(msg.payload.PID3_Kd),
            PID3_PV: parseFloat(msg.payload.PID3_PV),
            PID3_rawPV: parseFloat(msg.payload.PID3_rawPV),
            PID3_Bias: parseFloat(msg.payload.PID3_Bias),
            PID3_Output: parseFloat(msg.payload.PID3_Output)
        },
    }
];

return msg;

if (
    !msg.payload ||
    !msg.payload.temps_c ||
    !Array.isArray(msg.payload.temps_c) ||
    msg.payload.temps_c.length === 0
) {
    return null; // Don't process the message if temps are missing or malformed
}


let data = msg.payload;

// If payload is still a string, parse it
if (typeof data === "string") {
    data = JSON.parse(data);
}

let temps_c = data.temps_c;
let temps_k = data.temps_k;

// Build InfluxDB points
msg.payload = [
    {
        measurement: "RDXL6SD",
        fields: {
            TC1_C: temps_c[0],
            TC2_C: temps_c[1],
            TC3_C: temps_c[2],
            TC4_C: temps_c[3],
            RTD5_C: temps_c[4],
            RTD6_C: temps_c[5],
            TC1_K: temps_k[0],
            TC2_K: temps_k[1],
            TC3_K: temps_k[2],
            TC4_K: temps_k[3],
            RTD5_K: temps_k[4],
            RTD6_K: temps_k[5],
        }
    }
];

return msg;

if (
    !msg.payload ||
    !msg.payload.temps_c ||
    !Array.isArray(msg.payload.temps_c) ||
    msg.payload.temps_c.length === 0
) {
    return null; // Don't process the message if temps are missing or malformed
}


let data = msg.payload;

// If payload is still a string, parse it
if (typeof data === "string") {
    data = JSON.parse(data);
}

let temps_c = data.temps_c;
let temps_k = data.temps_k;

// Build InfluxDB points
msg.payload = [
    {
        measurement: "RDXL6SD_1",
        fields: {
            TC1_C: temps_c[0],
            TC2_C: temps_c[1],
            TC3_C: temps_c[2],
            TC4_C: temps_c[3],
            RTD5_C: temps_c[4],
            RTD6_C: temps_c[5],
            TC1_K: temps_k[0],
            TC2_K: temps_k[1],
            TC3_K: temps_k[2],
            TC4_K: temps_k[3],
            RTD5_K: temps_k[4],
            RTD6_K: temps_k[5],
        }
    }
];

return msg;

// Get stored start time
let t0 = context.get("t0");

// If first run, set start time
if (!t0) {
    t0 = Date.now();
    context.set("t0", t0);
}

// Compute elapsed time in seconds
const t = (Date.now() - t0) / 1000;

// Parameters
const rate = 1;   // K/s

// Linear cooldown
const cooldown = -rate * t;

msg.payload = cooldown;
msg.elapsed_s = t;

return msg;

const C2K = 273.15;

const rtd3_K = Math.round(100 * (parseFloat(msg.payload.RTD3) + C2K))/100;
const rtd4_K = Math.round(100 * (parseFloat(msg.payload.RTD4) + C2K))/100;

// store latest values so other nodes can read them
flow.set("RTD3_K", rtd3_K );
flow.set("RTD4_K", rtd4_K);

msg.payload = { RTD3_K: rtd3_K, RTD4_K: rtd4_K}
return msg;
